from agno import TeamAgent
from typing import Dict, Any

def detect_team_contradiction(team_results: Dict[str, Any], key_fact: str):
    positions = []
    for agent_name, result in team_results.items():
        position = result.get(key_fact)
        positions.append((agent_name, position))

    # Check for direct contradictions
    contradictions = []
    for i, (agent1, pos1) in enumerate(positions):
        for agent2, pos2 in positions[i+1:]:
            if pos1 and pos2 and pos1 != pos2:
                contradictions.append((agent1, agent2, pos1, pos2))
    return len(contradictions) > 0

# Usage
results = {'researcher': {'price': 'high'}, 'analyst': {'price': 'low'}}
has_contradiction = detect_team_contradiction(results, 'price')

