from agno import Agent
from pydantic import BaseModel, Field
from typing import List, Optional

class NestedAnalysis(BaseModel):
    findings: List[str]
    confidence: float = Field(ge=0.0, le=1.0)
    recommendations: Optional[List[str]] = None

class ProgressiveParser:
    @staticmethod
    def safe_parse(agent_output, schema):
        try:
            return schema.model_validate(agent_output)
        except ValidationError as e:
            # Fallback: extract critical fields
            return schema.model_validate_dict({
                'findings': agent_output.get('findings', []),
                'confidence': float(agent_output.get('confidence', 0.5))
            })

agent = Agent(output_schema=NestedAnalysis)
result = ProgressiveParser.safe_parse(agent.run('Analyze report'), NestedAnalysis)

